110	- (void)initTimerConfig {
111	    if (nil == self.keepAliveTimer)
112	    {
113	        NSTimeInterval currentTime = [XPUtility dateTimestamp];
114	        DLogTagInfo(kBLEHeartTag, @"initTimerConfig: 启动到开始耗时: %.3f秒", (currentTime - [XPAppStartTool getAppStartTime]) / 1000.0);
115	        @weakify(self)
116	        _systemStateQueue = dispatch_queue_create("com.example.timerQueue", DISPATCH_QUEUE_SERIAL);
117	        self.keepAliveTimer = [XPGCDTimer scheduledTimerWithTimeInterval:kBleHeartInterval repeats:YES queue:_systemStateQueue block:^{
118	            @strongify(self)
119	            NSTimeInterval timerTime = [XPUtility dateTimestamp];
120	            NSDictionary *sysInfo = [XPTrackHelper.shared getAppSystemInfo];
121	            if (!self.isWillSuspend) {
122	                if (self.lastSystemStateTime == 0 ) {
123	                    self.lastSystemStateTime = timerTime;
124	                    self.lastSystemInfo = sysInfo;
125	                    self.currentSystemStateTime = timerTime;
126	                    self.currentSystemInfo = sysInfo;
127	                } else {
128	                    self.lastSystemStateTime = self.currentSystemStateTime;
129	                    self.lastSystemInfo = self.currentSystemInfo;
130	                    self.currentSystemStateTime = timerTime;
131	                    self.currentSystemInfo = sysInfo;
132	                }
133	            }
134	            float timerDiff = (self.currentSystemStateTime - self.lastSystemStateTime) / 1000.0;
135	            if (timerDiff > kBleHeartInterval + 2) {
136	                DLogTagInfo(kBLEHeartTag, @"initTimerConfig: 定时器延迟超过2秒,系统调度可能异常,diffTime: %.3f秒", timerDiff);
137	                NSMutableDictionary *bussinessInfo = [NSMutableDictionary dictionary];
138	                bussinessInfo[kCarVinKey] = CTMediator.vin;
139	                bussinessInfo[kCarTypeKey] = CTMediator.defaultCarInfo.vehicleTypeCode;
140	                bussinessInfo[kTimerDurationKey] = @((long)timerDiff);
141	                bussinessInfo[kSinceAppStartDurationKey] = @((long)((self.currentSystemStateTime - [XPAppStartTool getAppStartTime]) / 1000.0));
142	                {
143	                    bussinessInfo[kCompareIndexKey] = @(1);
144	                    NSMutableDictionary *combinedInfo = [NSMutableDictionary dictionaryWithDictionary:self.lastSystemInfo];
145	                    [combinedInfo addEntriesFromDictionary:bussinessInfo];
146	                    [XPTrackHelper trackType:6 event:@"B069" module:@"P00004" label:[combinedInfo copy]];
147	                }
148	                {
149	                    bussinessInfo[kCompareIndexKey] = @(0);
150	                    NSMutableDictionary *combinedInfo = [NSMutableDictionary dictionaryWithDictionary:self.currentSystemInfo];
151	                    [combinedInfo addEntriesFromDictionary:bussinessInfo];
152	                    [XPTrackHelper trackType:6 event:@"B069" module:@"P00004" label:[combinedInfo copy]];
153	                }
154	            }
155	            if (self.isStart) {
156	                [self updateTimer:self.keepAliveTimer];
157	                DLogTagInfo(kBLEHeartTag, @"initTimerConfig 占用内存:%dM 可用内存:%dM CPU:%.02f%% 电量:%.02f%%  平均耗电:%.02f%%/小时 unity状态:%@ 保活:%@ 后台持续:%@ 后台保活累计:%@ 后台休眠:%@ 保活区间记录：%@", [[sysInfo valueForKey:kAppMemoryKey] intValue], [[sysInfo valueForKey:kAppFreeMemoryKey] intValue], [[sysInfo valueForKey:kCpuRateKey] floatValue], [[sysInfo valueForKey:kPhoneCurrentBatteryValueKey] floatValue], [self averageBattery], [sysInfo valueForKey:kUnityRunStateKey], [_aliveTimeDuration currentTimeAlive], [_aliveTimeDuration continuedTimeAlive], [_aliveTimeDuration totalTimeAlive], [_aliveTimeDuration totalSuspendTime], [_aliveTimeDuration totalAliveSections]);
158	            } else {
159	                DLogTagInfo(kBLEHeartTag, @"initTimerConfig 占用内存:%dM 可用内存:%dM CPU:%.02f%% 电量:%.02f%% unity状态:%@", [[sysInfo valueForKey:kAppMemoryKey] intValue], [[sysInfo valueForKey:kAppFreeMemoryKey] intValue], [[sysInfo valueForKey:kCpuRateKey] floatValue], [[sysInfo valueForKey:kPhoneCurrentBatteryValueKey] floatValue], [sysInfo valueForKey:kUnityRunStateKey]);
160	            }
161	        }];
162	    }
163	}
