213	- (NSString *)getNexAvailableBleName:(int)retryCount
214	{
215	    if (retryCount == CTMediator.defaultCarInfo.bleInfo.slaveInfos.count + 1) {
216	        return nil;
217	    }
218	    retryCount += 1;
219	    if (CTMediator.isPollingSecond) {
220	        self.sendedBlueIndex = 0;
221	        NSString *ecuName = CTMediator.defaultCarInfo.bleInfo.name;
222	        if ([XPBLEHandlerManager.manager getBleHandlerConnectState:ecuName] == XPBLEHanderConnectStateAuthorized) {
223	            return ecuName;
224	        } else {
225	            return nil;
226	        }
227	    } else {
228	        if (self.sendedBlueIndex == -1) {
229	            self.sendedBlueIndex = 0;
230	            NSString *ecuName = CTMediator.defaultCarInfo.bleInfo.name;
231	            if ([XPBLEHandlerManager.manager getBleHandlerConnectState:ecuName] == XPBLEHanderConnectStateAuthorized) {
232	                return ecuName;
233	            } else {
234	                return [self getNexAvailableBleName:retryCount];
235	            }
236	        } else if (self.sendedBlueIndex == CTMediator.defaultCarInfo.bleInfo.slaveInfos.count) {
237	            self.sendedBlueIndex = 0;
238	            NSString *ecuName = CTMediator.defaultCarInfo.bleInfo.name;
239	            if ([XPBLEHandlerManager.manager getBleHandlerConnectState:ecuName] == XPBLEHanderConnectStateAuthorized) {
240	                return ecuName;
241	            } else {
242	                return [self getNexAvailableBleName:retryCount];
243	            }
244	        } else {
245	            SlaveBLEMacAddressItem *item = CTMediator.defaultCarInfo.bleInfo.slaveInfos[self.sendedBlueIndex];
246	            NSString *ecuName = item.name;
247	            self.sendedBlueIndex += 1;
248	            if ([XPBLEHandlerManager.manager getBleHandlerConnectState:ecuName] == XPBLEHanderConnectStateAuthorized) {
249	                return ecuName;
250	            } else {
251	                return [self getNexAvailableBleName:retryCount];
252	            }
253	            return ecuName;
254	        }
255	    }
256	}
257	
258	- (void)sendHeartbeat
259	{
260	    if (!self.isStart) {
261	        return;
262	    }
263	    // 首先在左右蓝牙之间切换发送心跳，如果没有连接成功或者发送失败则尝试其他蓝牙
264	    // 现在是case by case处理，待今后优化成优雅一些的方法
265	    NSString *availableBle = [self getNexAvailableBleName:0];
266	    if ([NSString isEmptyWithString:availableBle])
267	    {
268	        self.heartbeatState = XPBleHeartbeatStateBluetoothNotAvailable;
269	    }
270	    else
271	    {
272	        // 蓝牙心跳指令发送
273	        [self innerSendHeartbeatByBlueIndex:availableBle];
274	        
275	        self.heartbeatState = XPBleHeartbeatStateAlive;
276	    }
277	}
278	
279	- (void)innerSendHeartbeatByBlueIndex:(NSString *)ecuName
280	{
281	    DLogTagError(kBLEHeartTag, @"使用 %@ 蓝牙发送心跳",ecuName);
282	    [self innerSendHeartbeat:ecuName];
283	}
284	
285	- (void)innerSendHeartbeat:(NSString *)ecuName
286	{
287	    @weakify(self);
288	    [_bleViewModel sendHeartbeatWithBleEcuName:ecuName success:^{
289	        @strongify(self);
290	        DLogTagInfo(kBLEHeartTag, @"===> 发送蓝牙心跳指令成功");
291	        self.retrySendedCount = 0;
292	        
293	        if(!self.isFirstSendHeartbeatSuccess) {
294	            self.isFirstSendHeartbeatSuccess = YES;
295	            [XPStatisticsMgr sendEvent:XP_MOBILE_CARCONTROL_FIRST_SEND_HEAT_JUMP_SUCCESS module:XP_MOBILE_CARCONTROL_MODULE];
296	            DLogTagInfo(kBLEHeartTag, @"启动保活后第一次发送蓝牙心跳成功埋点：event:%@", XP_MOBILE_CARCONTROL_FIRST_SEND_HEAT_JUMP_SUCCESS);
297	        }
298	    } failure:^(NSError * _Nullable error) {
299	        @strongify(self);
300	        if (self.retrySendedCount >= 3) // 已经重试过三次
301	        {
302	            DLogTagInfo(kBLEHeartTag, @"^^^ ===> 发送心跳指令失败%@ 已经重试过 %@ 次，不再重试", error, @(self.retrySendedCount));
303	            
304	            self.heartbeatState = XPBleHeartbeatStateBluetoothNotAvailable;
305	            self.retrySendedCount = 0;
306	        }
307	        else
308	        {
309	            DLogTagInfo(kBLEHeartTag, @"^^^ ===> 发送心跳指令失败%@ 尝试第 %@ 次重试", error, @(self.retrySendedCount + 1));
310	            
311	            // 发送失败，重试
312	            self.retrySendedCount ++;
313	            [self sendHeartbeat];
314	        }
315	    }];
316	}
317	
318	- (float)averageBattery
319	{
320	    CFAbsoluteTime time = CFAbsoluteTimeGetCurrent();
321	    float batteryLevel = [[[XPTrackHelper.shared getAppSystemInfo] valueForKey:kPhoneCurrentBatteryValueKey] floatValue];
322	    float dt = time - _backgroundTimeBegin;
323	    float dbl = _backgroundBatteryLevel - batteryLevel;
324	
325	    float ret = dbl * 60 * 60 / dt;
326	    return ret;
327	}
328	
