329	- (void)setUpSettingsMonitor
330	{
331	    static dispatch_once_t onceToken;
332	    dispatch_once(&onceToken, ^{
333	        
334	        DLogTagInfo(kBLEKeyPollingTag, @"<PA>启动Polling和摇一摇开关监听");
335	        
336	        [self checkPullAliveCondition];
337	
338	        RACSubject *endSubject = [RACSubject subject];
339	        __weak typeof(self) weakself = self;
340	        [[RACObserve([XPMultiBleManager sharedManager], pollingRunMode) takeUntil:endSubject].distinctUntilChanged.deliverOnMainThread subscribeNext:^(id  _Nullable x) {
341	            __strong typeof(self) self = weakself;
342	            PollingRunMode mode = (PollingRunMode)[x intValue];
343	            DLogTagInfo(kKeepAliveTag, @"<PA>监听到Polling状态发生变化：%@", @(mode));
344	            self.pollingSwitchOn = (PollingRunModeNone != mode);
345	        }];
346	        
347	        RACSubject *endSubjectIBeacon = [RACSubject subject];
348	        [[RACObserve([XPIBeaconPullAlive sharedInstance], locationAuthorizationStatus) takeUntil:endSubjectIBeacon].distinctUntilChanged.deliverOnMainThread subscribeNext:^(id  _Nullable x) {
349	            __strong typeof(self) self = weakself;
350	            NSUInteger status = [x unsignedIntValue];
351	            DLogTagInfo(kKeepAliveTag, @"<PA>监听到定位权限发生变化：%@(%@)", @(status), [self locationAuthorizationStatusToString:status]);
352	            [self checkPullAliveCondition];
353	        }];
354	        
355	        RACSubject *endSubjectAccuracy = [RACSubject subject];
356	        [[RACObserve([XPIBeaconPullAlive sharedInstance], accuracyLocationSwitch) takeUntil:endSubjectAccuracy].distinctUntilChanged.deliverOnMainThread subscribeNext:^(id  _Nullable x) {
357	            __strong typeof(self) self = weakself;
358	            BOOL accuracy = [x boolValue];
359	            DLogTagInfo(kKeepAliveTag, @"<PA>监听到精确位置开关发生变化：%@", @(accuracy));
360	            [self checkPullAliveCondition];
361	        }];
362	        
363	        [[CTMediator.defaultCarSwitchedSignal.deliverOnMainThread takeUntil:self.rac_willDeallocSignal] subscribeNext:^(MyCarInfo* _Nullable defaultCarInfo) {
364	            DLogTagInfo(kKeepAliveTag, @"<PA>监听到车辆信息已准备好：%@", defaultCarInfo.vin);
365	            [self checkPullAliveCondition];
366	            
367	            // 检测拉活信息
368	            
369	            NSString *mainBleMacAddress = [XPBLEKeyManager getCurrentBleMacAddress];
370	            NSString * mainUUID = [self uuidFromMac:mainBleMacAddress];
371	
372	            if (mainUUID) {
373	                [[XPIBeaconPullAlive sharedInstance] checkUUIDInSysInfo:@[mainUUID] vin:[CTMediator vin]];
374	            }
375	        }];
376	        
377	        [self.rac_deallocDisposable addDisposable:[[NSNotificationCenter.defaultCenter rac_addObserverForName:XPVehicleNotificationVehicleSwitched object:nil].deliverOnMainThread subscribeNext:^(NSNotification * _Nullable notification) {
378	            __strong typeof(self) self = weakself;
379	            DLogTagInfo(kKeepAliveTag, @"<PA>监听到车辆信息已准备好：%@", XPVehicleSDK.shared.vehicleManager.currentVehicleData.vin);
380	            [self checkPullAliveCondition];
381	            
382	            // 检测拉活信息
383	            
384	            NSString *mainBleMacAddress = [XPBLEKeyManager getCurrentBleMacAddress];
385	            NSString * mainUUID = [self uuidFromMac:mainBleMacAddress];
386	
387	            if (mainUUID) {
388	                [[XPIBeaconPullAlive sharedInstance] checkUUIDInSysInfo:@[mainUUID] vin:[CTMediator vin]];
389	            }
390	        }]];
391	
392	        dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(2.0 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
393	            // 蓝牙钥匙存在也开启 iBeacon 拉活，还需要在第一次创建蓝牙钥匙时调用 registerIBeacons
