593	- (void)registerIBeacons
594	{
595	    if ([CTMediator isSDK2ndCar]) {
596	        DLogTagInfo(kBLEKeyPollingTag, @"Mona车型，不注册iBeacon");
597	        return;
598	    }
599	        
600	    // 收到车辆切换会注销前车iBeacon，注册iBeacon可能会更早执行，因此需要延时，不然会先注册，紧接着注销，不符合预期
601	    dispatch_async(dispatch_get_global_queue(0, 0), ^{
602	
603	        self.beaconUUIDs = [NSMutableArray arrayWithCapacity:4];
604	        NSString *mainBleMacAddress = [XPBLEKeyManager getCurrentBleMacAddress];
605	        NSString * mainUUID = [self uuidFromMac:mainBleMacAddress];
606	        if (mainUUID.length > 0)
607	        {
608	            [self.beaconUUIDs addObject:mainUUID];
609	        }
610	        
611	        for (int i = 0; i < 10; ++i) {
612	            NSString * chengedUUID = [self uuidFromMac:mainBleMacAddress changeIndex:i];
613	            if (chengedUUID.length > 0)
614	            {
615	                [self.beaconUUIDs addObject:chengedUUID];
616	            }
617	        }
618	        
619	        DLogTagInfo(kBLEKeyPollingTag, @"尝试注册iBeacon 主蓝牙: %@", mainUUID);
620	
621	        if (CTMediator.isPollingFirst) {
622	            for (int i = 0; i < CTMediator.defaultCarInfo.bleInfo.slaveInfos.count; i++)
623	            {
624	                SlaveBLEMacAddressItem *item = [CTMediator.defaultCarInfo.bleInfo.slaveInfos objectAtIndex:i];
625	                NSString * uuidStr = [self uuidFromMac:item.mac];
626	                if (mainUUID.length > 0)
627	                {
628	                    [self.beaconUUIDs addObject:uuidStr];
629	                }
630	            }
631	        }
632	
633	        [[XPIBeaconPullAlive sharedInstance] startWithUUIDs:self.beaconUUIDs vin:[CTMediator vin]];
634	
635	    });
636	}
