638	- (NSString *)uuidFromMac:(NSString *)mac {
639	    if (mac.length <= 0)
640	    {
641	        return nil;
642	    }
643	    
644	    NSString *uuidString = [NSString stringWithFormat:@"58C1F550-BBAA-45EC-F556-%@", [[mac stringByReplacingOccurrencesOfString:@":" withString:@""] uppercaseString]];
645	    DLogTagInfo(kBLEKeyPollingTag, @"iBeacon uuid string是: %@", uuidString);
646	    return uuidString;
647	}
