94	    RACSubject *endSubject = [RACSubject subject];
95	    __weak typeof(self) weakself = self;
96	    [[[RACObserve(heartbeat, heartbeatState) takeUntil:endSubject] skip:1].distinctUntilChanged.deliverOnMainThread subscribeNext:^(id  _Nullable x) {
97	        __strong typeof(self) self = weakself;
98	        XPBleHeartbeatState state = (XPBleHeartbeatState)[x intValue];
99	        DLogTagInfo(kBLEKeyPollingTag, @"<PA>监听到蓝牙心跳保活状态发生变化：%@", @(state));
100	        if (XPBleHeartbeatStateBluetoothNotAvailable == state)
101	        {
102	            NSTimeInterval backgroundTimeRemaining = self.generalAlive.backgroundTimeRemaining;
103	            DLogTagInfo(kKeepAliveTag, @"监听到没有蓝牙可用，无法使用心跳保活，后台任务保活剩余时间：%.02f秒 keepAliveState:%@", (backgroundTimeRemaining == DBL_MAX) ? -1 :  backgroundTimeRemaining, @(self.keepAliveState));
104	            self.bluetoothNotAvailable = YES;
105	            if ([self.generalAlive backgroundTimeRemaining] < 10)
106	            {
107	                if (XPBLEKeepAliveStateWillInvalid != self.keepAliveState)
108	                {
109	                    self.keepAliveState = XPBLEKeepAliveStateWillInvalid;
110	                    if (self.willKeepAliveFailBlock)
111	                    {
112	                        self.willKeepAliveFailBlock();
113	                    }
114	                }
115	            }
116	            else if ([self.generalAlive backgroundTimeRemaining] < 1)
117	            {
118	                self.keepAliveState = XPBLEKeepAliveStateDidInvalid;
119	            }
120	        }
121	        else if (XPBleHeartbeatStateAlive == state)
122	        {
123	            DLogTagInfo(kKeepAliveTag, @"监听蓝牙心跳保活转为正常");
124	            self.bluetoothAvailableEvent = YES;
125	            self.bluetoothNotAvailable = NO;
126	            self.keepAliveState = XPBLEKeepAliveStateAlive;
127	        }
128	    }];
129	
130	    
131	    RACSubject *endSubject2 = [RACSubject subject];
132	    [[[RACObserve(_generalAlive, backgroundTimeRemaining) takeUntil:endSubject2] skip:1].distinctUntilChanged.deliverOnMainThread subscribeNext:^(id  _Nullable x) {
133	            __strong typeof(self) self = weakself;
134	            NSTimeInterval backgroundTimeRemaining = self.generalAlive.backgroundTimeRemaining;
135	            DLogTagInfo(kKeepAliveTag, @"后台任务保活剩余时间：%.02f秒 keepAliveState:%@ bluetoothNotAvailable:%@", (backgroundTimeRemaining == DBL_MAX) ? -1 :  backgroundTimeRemaining, @(self.keepAliveState), @(self.bluetoothNotAvailable));
136	            if (backgroundTimeRemaining < 10)
137	            {
138	                if (self.bluetoothNotAvailable)
139	                {
140	                    if (XPBLEKeepAliveStateWillInvalid != self.keepAliveState)
141	                    {
142	                        self.keepAliveState = XPBLEKeepAliveStateWillInvalid;
143	                        if (self.willKeepAliveFailBlock)
144	                        {
145	                            self.willKeepAliveFailBlock();
146	                        }
147	                    }
148	                }
149	            }
150	            
151	            if (backgroundTimeRemaining < 1)
152	            {
153	                 self.keepAliveState = XPBLEKeepAliveStateDidInvalid;
154	            }
155	        }];
156	    
157	    RACSubject *endSubject3 = [RACSubject subject];
158	    [[[RACObserve([XPIBeaconPullAlive sharedInstance], iBeaconState) takeUntil:endSubject3] skip:1].distinctUntilChanged.deliverOnMainThread subscribeNext:^(id  _Nullable x) {
159	            __strong typeof(self) self = weakself;
160	        XPIBeaconState state = (XPIBeaconState)[x intValue];
161	        if (XPIBeaconStateEnter == state || XPIBeaconStateLeave == state)
162	        {
163	            if (UIApplicationStateBackground == _applicationInitState)
164	            {
165	                CFAbsoluteTime currTime = CFAbsoluteTimeGetCurrent();
166	                if ((currTime - _launchTime) < 15) //  15秒内有iBeacon信号算拉活
167	                {
168	                    if (NO == _aliveByPull)
169	                    {
170	                        _aliveByPull = YES;
171	                        DLogTagInfo(kBLEKeyPollingTag, @"%@", @"检测到该次启动属于iBeacon拉活");
172	                    }
173	                }
174	            }
175	        }
176	    }];
177	}
