16	@implementation XPGCDTimer
17	
18	+ (XPGCDTimer *)scheduledTimerWithTimeInterval:(NSTimeInterval)interval
19	                                     repeats:(BOOL)repeats
20	                                       block:(void (^)(void))block {
21	    return [self scheduledTimerWithTimeInterval:interval repeats:repeats queue:dispatch_get_main_queue() block:block];
22	}
23	
24	+ (XPGCDTimer *)scheduledTimerWithTimeInterval:(NSTimeInterval)interval
25	                                     repeats:(BOOL)repeats
26	                                       queue:(dispatch_queue_t)queue
27	                                       block:(void (^)(void))block {
28	    return [[XPGCDTimer alloc] initWithInterval:interval
29	                                                 repeats:repeats
30	                                                   queue:queue
31	                                                   block:block];
32	}
33	
34	- (instancetype)initWithInterval:(NSTimeInterval)interval
35	                         repeats:(BOOL)repeats
36	                           queue:(dispatch_queue_t)queue
37	                           block:(void (^)(void))block {
38	    self = [super init];
39	    if (self) {
40	        self.timer = dispatch_source_create(DISPATCH_SOURCE_TYPE_TIMER, 0, 0, queue);
41	        dispatch_source_set_timer(self.timer, dispatch_time(DISPATCH_TIME_NOW, interval * NSEC_PER_SEC), interval * NSEC_PER_SEC, 0);
42	        dispatch_source_set_event_handler(self.timer, ^{
43	            if (!repeats) {
44	                dispatch_source_cancel(self.timer);
45	            }
46	            block();
47	        });
48	        dispatch_resume(self.timer);
49	    }
50	    return self;
51	}
52	
53	- (void)dealloc {
54	    [self invalidate];
55	}
56	
57	- (void)invalidate {
58	    if (self.timer) {
59	        dispatch_source_cancel(self.timer);
60	    }
61	}
62	
63	
64	@end
