65	- (NSString *)timeDurrationStr:(NSInteger)seconds
66	{
67	    NSInteger hour = seconds / 60 / 60;
68	    NSInteger minute = (seconds / 60) % 60;
69	    NSInteger sec = seconds % 60;
70	
71	    return [NSString stringWithFormat:@"%@小时%@分钟%@秒", @(hour), @(minute), @(sec)];
