163	- (NSString *)totalAliveSections
164	{
165	    NSString * sections = @"";
166	    float duration = 0;
167	    CFAbsoluteTime tmStart = 0;
168	    NSInteger count = [_heartbeatTimeSections count];
169	    if (count == 0) {
170	        return @"";
171	    }
172	    for (int i = 0; i < count; ++i)
173	    {
174	        NSNumber * num = [_heartbeatTimeSections objectAtIndex:i];
175	        CFAbsoluteTime tm = [num doubleValue];
176	        if (0 == (i % 2))
177	        {
178	            tmStart = tm;
179	        }
180	        else
181	        {
182	            CFAbsoluteTime tmEnd = tm;
183	            duration = (tmEnd - tmStart);
184	            
185	            NSString * section = [self makeSectionWithStart:tmStart end:tmEnd];
186	            if ([sections length] > 0)
187	            {
188	                sections = [NSString stringWithFormat:@"%@, %@", sections, section];
189	            }
190	            else
191	            {
192	                sections = [NSString stringWithFormat:@"%@", section];
193	            }
194	        }
195	    }
196	    
197	    CFAbsoluteTime tmEnd = CFAbsoluteTimeGetCurrent();
198	    NSString * section = [self makeSectionWithStart:tmStart end:tmEnd];
199	    if ([sections length] > 0)
200	    {
201	        sections = [NSString stringWithFormat:@"[%@, %@]", sections, section];
202	    }
203	    else
204	    {
205	        sections = [NSString stringWithFormat:@"[%@]", section];
206	    }
207	 
208	    return sections;
209	}
210	
211	- (NSString *)makeSectionWithStart:(CFAbsoluteTime)start end:(CFAbsoluteTime)end
212	{
213	    NSString * startStr = [[self class] absoluteTimeToShortString:start];
214	    NSString * endStr = [[self class] absoluteTimeToShortString:end];
215	    NSString * lengthStr  = [self timeDurrationSimple:(end - start)];
216	    
217	    NSString * section = [NSString stringWithFormat:@"%@(%@ ~ %@)", lengthStr, startStr , endStr];
218	    
219	    return section;
220	}
221	
222	
223	- (float)totalAliveDuration
224	{
225	    float duration = 0;
226	    CFAbsoluteTime tmStart = 0;
227	    NSInteger count = [_heartbeatTimeSections count];
228	    if (count == 0) {
229	        return 0;
230	    }
231	    for (int i = 0; i < count; ++i)
232	    {
233	        NSNumber * num = [_heartbeatTimeSections objectAtIndex:i];
234	        CFAbsoluteTime tm = [num doubleValue];
235	        if (0 == (i % 2))
236	        {
237	            tmStart = tm;
238	        }
239	        else
240	        {
241	            CFAbsoluteTime tmEnd = tm;
242	            duration += (tmEnd - tmStart);
243	        }
244	    }
245	    
246	    // 后台运行时，count 一定是单数，所以要加上当前最后一段活动时间
247	    CFAbsoluteTime tmEnd = CFAbsoluteTimeGetCurrent();
248	    duration += (tmEnd - tmStart);
249	
250	    return duration;
251	}
252	
253	- (float)totalSuspendDuration
254	{
255	    float duration = 0;
256	    CFAbsoluteTime susStart = 0;
257	    NSInteger count = [_heartbeatTimeSections count];
258	    if (count == 0) {
259	        return 0;
260	    }
261	    for (int i = 0; i < count; ++i)
262	    {
263	        NSNumber * num = [_heartbeatTimeSections objectAtIndex:i];
264	        CFAbsoluteTime tm = [num doubleValue];
265	        if (0 == (i % 2))
266	        {
267	            if (susStart > 0)
268	            {
269	                CFAbsoluteTime susEnd = tm;
270	                duration += (susEnd - susStart);
271	            }
272	        }
273	        else
274	        {
275	            susStart = tm;
276	        }
277	    }
278	    
279	    return duration;
280	}
281	
282	- (NSString *)totalSuspendTime
283	{
284	    float dur = [self totalSuspendDuration];
285	    if (dur < 0.001)
286	    {
287	        return @"0";
288	    }
289	    
290	    return [self timeDurrationStr:dur];
291	}
